var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……인정해 드리죠. 루나의 태업이 예상 이상으로 기력을 소진하게 했군요.","JPN":"……認めましょう。ルナのサボタージュで予想以上に力を消耗させられました。","ENG":"I'll admit that Luna's sabotage caused me to expend more energy than expected.","TWN":"……我承認，露娜的怠工消耗了比我預想得更多的體力。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 불러들인 침식체들도 어째서인지 오지 않는 걸요.","JPN":"マエストロ、呼び寄せた侵食体もなぜか来ません。","ENG":"Chief Conductor, the C.O.s are not responding to our summons.","TWN":"指揮家，召喚的那些侵蝕體不知道為什麼也沒有來。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 곤란한걸. 이러면 루나를 데려오는 편이 나았겠는데.","JPN":"ふーん、困ったわね。これじゃあ、ルナを連れてきた方がよかったかも。","ENG":"Hmm, that's not good. Now, it seems as if it would've been better to bring Luna here instead.","TWN":"嗯，這下麻煩了。早知道這樣，還不如把露娜帶過來了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"부상자들은 후방으로! 탄환을 아끼지 마!","JPN":"怪我人は後方に！　弾丸を惜しむな！","ENG":"Send the wounded to the back! Don't spare any bullets!","TWN":"傷患退後！不要吝嗇彈藥！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 학회원들도 가세하기 시작했습니다.","JPN":"副戦隊長、学会員も加勢しはじめました。","ENG":"Deputy Commander, the Society members have started to fight back!","TWN":"副隊長，學會成員也開始加入了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"전투가 길어질수록 불리한 건 우리 쪽이긴 하지.","JPN":"戦闘が長引くほど不利になるのは俺たちの方だ。","ENG":"We are only digging our own graves by prolonging this fight.","TWN":"戰鬥時間拖得越長，對我們越不利。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제일 강한 전력은 시간에 제약이 있으니 말이야.","JPN":"最強の戦力は時間に制限があるからな。","ENG":"Our strongest weapon can only operate for a limited time.","TWN":"因為最強大的戰鬥力有時間限制。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 아껴 두고 있지 않습니까.","JPN":"だから、温存しているのではないですか。","ENG":"That's why I'm saving it for later.","TWN":"所以才一直保留著不是嗎。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"안 보이는 주제에 이리저리 잘만 피해대는 침식체입니다. 발을 묶기 전까지 투자는 리스크가 크죠.","JPN":"目が見えないくせに、あちこち上手く逃げ回る侵食体です。足止めをする以前の投資はリスクが大きすぎます。","ENG":"This C.O. is blind, but she's able to avoid all of our attacks. We can't risk it until we corner her.","TWN":"她可是個明明看不見，卻總能成功躲避的侵蝕體。在困住她的手腳之前，投資的風險很大。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"공기가 바뀌었다.","JPN":"空気が変わった。","ENG":"The air changed.","TWN":"空氣變了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"공기……?","JPN":"空気……？","ENG":"The air...?","TWN":"空氣……？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇군요. 냉각기를 가동하지 않아도 될 만큼 기온이 감소했습니다.","JPN":"本当ですね。冷却器を使わなくてもいいほどに気温が低下しています。","ENG":"I see. The temperature has fallen enough so that I don't have to activate my cooling devices.","TWN":"是啊。氣溫下降了很多，都不用開冷氣了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"갑자기 눈이 내리네. 침식 현상 탓인가?","JPN":"いきなり雪が降ってきたわね。侵食現象のせいかしら。","ENG":"It's snowing all of a sudden. Is this due to the Counterside Effect?","TWN":"突然下雪了呢，是因為侵蝕現象嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……아뇨. 귀빈께서 오셨습니다.","JPN":"……いいえ。貴賓がお越しになりました。","ENG":"...No. Our VIP has arrived.","TWN":"……不，是有貴賓來了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"과연 왕께서 집착하시기에 부족함이 없는 자질이군요.","JPN":"なるほど、王様が執着するに足る資質です。","ENG":"Indeed, she is a worthy talent of our lord's obsession.","TWN":"果然是值得王執著的資質。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 힘……. 그것도 순수한 인간의 몸으로. 경이로워요.","JPN":"この力……それも純粋な人間の身体で。驚異的です。","ENG":"This strength... from a mere human. Astounding.","TWN":"這股力量……還是以純粹的人類之軀，真是令人驚歎。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"결과가 어떻든, 의식은 곧 완성되겠군요.","JPN":"結果はどうであれ、もうすぐ儀式は完成されますね。","ENG":"No matter the results, the ritual will soon be complete.","TWN":"無論結果如何，儀式就快完成了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"자, 연주에 보다 박차를 가해 볼까요.","JPN":"さあ、演奏に拍車をかけましょう。","ENG":"Let's raise the tempo, shall we?","TWN":"好了，讓我們加快演奏速度吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"흠, 흐흠, 흠……","JPN":"ふーん、ふふーん、ふーん……","ENG":"*Humming*","TWN":"嗯，嗯，嗯……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"루나라고 했죠. 음악은 정말 흥미롭지 않나요?","JPN":"ルナでしたね。音楽って本当に興味深くないですか？","ENG":"Luna, was it? Isn't music fascinating?","TWN":"你叫露娜是吧，音樂真的很有意思不是嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"앗, 네? 저, 전 드셔도 맛이 없는데요?","JPN":"あっ、はい？　あ、アタシは食べても美味しくないですよ？","ENG":"H-huh? I-I don't taste good...","TWN":"啊，嗯？我、我一點都不好吃的？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"인류 문명에서 음악과 춤은 예술의 탄생과 동시에 잉태되었답니다.","JPN":"人類の文明で音楽と踊りは、芸術の誕生と同時に生まれました。","ENG":"Music and dance emerged alongside the birth of art in human civilization.","TWN":"在人類的文明中，音樂和舞蹈伴隨著藝術的誕生而孕育。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"짐승과 같았던 인류가 함께 춤을 추고 노래를 부르면서, 서로의 감정을 재현하고 다른 이들에게 전이시켰죠.","JPN":"獣のようであった人類が、一緒に踊り歌いながらお互いの感情を再現し、他の者たちに転移させたのです。","ENG":"At the time, humanity, which resembled beasts, danced and sang together, recreating and transmitting each other's emotions.","TWN":"曾經和野獸一樣的人類，開始一起唱歌、跳舞，再現彼此的感情並傳達給了其他人。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"모든 주문이 고유한 리듬을 가지는 것과 비슷해요.","JPN":"すべての呪文が固有のリズムを持っているのと似ています。","ENG":"It's similar to how all spells have their unique rhythm.","TWN":"就如所有咒語都有固定的節奏一樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"말이 통하지 않는 존재에게도 음악은 소통의 수단으로 작용하거든요.","JPN":"言葉が通じない存在相手にも、音楽はコミュニケーションの手段になりますからね。","ENG":"Music served as a means of communication even for creatures unable to communicate using language.","TWN":"因為對於語言不通的存在來說，音樂也是溝通的手段。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"인간을 신으로 빚어냈던 여러분의 문명이 음악에 기반한 건, 결코 우연이 아니랍니다.","JPN":"人間を神として作り出した皆さんの文明が音楽に基づいているのは、決して偶然ではありません。","ENG":"Consequently, it was no accident that your civilization, which created a human as a god, is based on music.","TWN":"你們的文明將人類塑造成神，也是基於音樂實現的，這絕非偶然。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그…… 그렇군요. 전 이교도 출신이라 자세한 역사는 잘 모르지만요.","JPN":"そ……そうなんですね。アタシは異教徒出身で、詳しい歴史は知らないんですけど。","ENG":"I-I see. I was from a pagan, so I don't know that much about history.","TWN":"啊……這樣啊。我是異教徒出身，所以不知道詳細的歷史。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저기…… 그런데, 저대로 계속 싸우게 둬도 되나요?","JPN":"あの……でも、あのまま戦わせていいんですか？","ENG":"Um... But, shouldn't we stop them from fighting?","TWN":"那個……不過，繼續讓她們戰鬥下去也沒關係嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"왜요? 걱정되세요?","JPN":"どういう意味ですか？　心配なのですか？","ENG":"Why is that? Are you worried?","TWN":"怎麼？你很擔心？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아뇨. 그, 부학회장님이 휘말리면 곤란하지 않으신가 해서……","JPN":"いえ。あの、副学会長が巻き込まれたら困るんじゃないかなーって……","ENG":"No. I just thought there might be a bit of trouble if the Vice President got involved...","TWN":"不是，那個，我在想副學會長被捲進去的話，你會不會很為難……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"조금만…… 도와 주시면 안 될까요?","JPN":"ちょっとだけ……助けてくれませんか？","ENG":"Shouldn't you... help them a little bit?","TWN":"不能……幫幫她嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗. 동료들을 생각해서 한 말이었군요.","JPN":"ふふっ。仲間を思ってのことでしたか。","ENG":"Haha. So you were worried about your fellow members.","TWN":"呵呵，原來你是為夥伴們著想才這麼說的啊。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어째서 네퀴티아가 당신을 추천했는지 알 것 같아요.","JPN":"どうしてネキティアがあなたを勧めたのか、わかるような気がします。","ENG":"Now we see why Nequitia recommended you.","TWN":"我們好像知道莉奎蒂亞為什麼會推薦你了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"육체는 성숙했으면서 정신은 미숙한 그림자라…… 군침이 도네요.","JPN":"肉体は成熟していながら、精神は未熟であるシャドウ……涎が出ますね。","ENG":"A mentally immature Shadow in a mature body... The sound of it makes our mouth water.","TWN":"身體很成熟，但精神卻不成熟的暗影……口水都要流下來了呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저, 전 드셔도 맛이 없다니까요!","JPN":"あ、アタシは食べても美味しくないですって！","ENG":"I-I don't taste good!","TWN":"我…我真的一點都不好吃！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 그럴지도 모르죠.","JPN":"もちろんそうかもしれません。","ENG":"Perhaps so.","TWN":"或許吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하지만 취향은 제각각이니 먹어 봐야 알 수 있지 않을까요?","JPN":"ですが好みというものは人それぞれですから、食べてみないとわからないのでは？","ENG":"But taste is subjective. They say one can only know from trying it for themselves, no?","TWN":"不過每個人的口味都不一樣，所以要嚐過之後才知道吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"두려워하지 마세요. 핵은 살짝 맛만 보고 남겨 드릴게요.","JPN":"怖がらないでください。核はちょっと味見だけして、残してあげます。","ENG":"Don't be afraid. We'll just sample your core and then leave the rest.","TWN":"別害怕，核心我就只嚐一口，剩下的會留給你的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"가엾은 네퀴티아. 스스로 도려낼 수 없게 된 나머지 소중한 악기를 제물로 바치다니.","JPN":"かわいそうなネキティア。自分では切り離せないあまり、大事な楽器を供え物として捧げるなんて。","ENG":"Poor Nequitia. She had to sacrifice her precious instrument because she could not cut off it by herself.","TWN":"可憐的莉奎蒂亞，明明自己都不能放棄，卻還要把最寶貴的樂器當成祭物獻出來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아…… 아아……. 아…….","JPN":"あ……ああ……あ……","ENG":"Ah... Aah... Ah...","TWN":"啊……啊啊……啊……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"사사사사살려─","JPN":"たたたた助け……","ENG":"P-p-p-plea–","TWN":"救救救救命啊——"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>에델.\\n당신은 오랫동안 나를 원해 왔죠.</color>","JPN":"<color=#ff3636>エデル。\\nあなたは長らく私を欲してきましたね。</color>","ENG":"<color=#ff3636>Edel.\\nYou have long wanted me.</color>","TWN":"<color=#ff3636>艾瑟兒，\\n你一直很想得到我吧。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>아무리 외면하고 거부해도, 당신을 바라봐 준 사람은 저뿐이니까.</color>","JPN":"<color=#ff3636>いくら目を背け拒んでも、あなたに目を向けてくれた人は私だけでしたから。</color>","ENG":"<color=#ff3636>Regardless of how many times I turned away, I was the only person who truly saw you.</color>","TWN":"<color=#ff3636>因為不管我怎麼逃避和拒絕，你的眼裡只有我。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 이제는 아닙니다.</color>","JPN":"<color=#ff3636>ですが、もう違います。</color>","ENG":"<color=#ff3636>But not anymore.</color>","TWN":"<color=#ff3636>不過現在不是了。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>저도 당신을 원해요, 에델.</color>","JPN":"<color=#ff3636>私もあなたを欲します、エデル。</color>","ENG":"<color=#ff3636>I want you as well, Edel.</color>","TWN":"<color=#ff3636>我也想要你，艾瑟兒。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……오셨군요, 레지나 님.","JPN":"……いらっしゃいましたね、レジーナ様。","ENG":"...You're here, Miss Regina.","TWN":"……你來了，蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"예상대로 시간을 동결시키는 건 통하지 않는군요.","JPN":"予想どおり、時間を凍結させる手は通じませんわね。","ENG":"As expected, freezing time didn't work on you.","TWN":"跟我預想的一樣，結凍時間果然不管用。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부, 부학회장……?","JPN":"ふ、副学会長……？","ENG":"V-Vice President...?","TWN":"副…副學會長……？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……그래요, 접니다. 레지나 맥크레디.","JPN":"……はい、私です。レジーナ・マクレディー。","ENG":"Yes, it is me. Regina MacCready.","TWN":"……是的，是我，蕾佳娜·麥克蕾蒂。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"시간을 끌어 주었군요. 사장님이 포석을 놓는 방식도 이해가 가네요.","JPN":"時間を稼いでくれたのですね。社長が布石を打つ方法も理解できました。","ENG":"You bought me time. Now I understand what Boss meant by laying the groundwork.","TWN":"是你幫我拖延了時間。現在我也能理解老闆說的那步棋，是什麼意思了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"여기를 떠나세요, 루나.","JPN":"ここから離れてください、ルナ。","ENG":"You should leave, Luna.","TWN":"離開這裡吧，露娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"하지만, 밖에서 최고 지휘자님이……","JPN":"でも、外でマエストロが……","ENG":"But Chief Conductor is outside...","TWN":"可是，首席指揮家正在外面……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"악단에 합류한다고 해도 말리지 않습니다.","JPN":"楽団に合流するとしても、止めません。","ENG":"I will not stop you if you choose to rejoin the Orchestra.","TWN":"就算你說要回到樂團，我也不會阻止你。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이 곳에 더 이상 머물지만 마세요. 제가 당신에게 해 줄 수 있는 편의는 그것뿐입니다.","JPN":"もうこれ以上ここに留まらないでください。私があなたにしてあげられるのはそれだけです。","ENG":"But I urge you to leave here. That is the last act of kindness I will extend to you.","TWN":"只要不待在這裡就好。我能為你提供的方便就只有這些了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"미, 미안했어…….","JPN":"ま、前はごめんね……","ENG":"I-I'm sorry for what happened...","TWN":"對…對不起……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……괜찮아요. 저 역시 그랬을 테니까.","JPN":"……いいんです。私もまたそうしたでしょうから。","ENG":"...Not to worry. I also would have been.","TWN":"……沒關係，因為我也會那麼做。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"오래 기다렸죠, 에델.","JPN":"待たせましたね、エデル。","ENG":"Apologies for keeping you waiting, Edel.","TWN":"讓你久等了，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"다녀왔어요.","JPN":"今帰りました。","ENG":"I'm home.","TWN":"我回來了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};